// One item per file (the SplitInBatches downstream will group them in chunks of batchSize).
const cfg = $input.first().json;
const files = Array.isArray(cfg.files) ? cfg.files : [];
return files.map(f => ({ json: { id: f.id, name: f.name, mimeType: f.mimeType || 'image/jpeg', shard_id: cfg.shard_id, run_id: cfg.run_id } }));

// Convert each binary into base64 + re-attach original file metadata
// (Drive Download replaces the item, so we look up {id,name,shard_id,run_id}
//  from Fan Out Files via itemMatching on the paired index).
const items = $input.all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const it = items[i];
  let orig = {};
  try { orig = $('Fan Out Files').itemMatching(i).json || {}; } catch(e) { orig = it.json || {}; }
  let imageBase64 = null, imageMimeType = null;
  try {
    const buf = await this.helpers.getBinaryDataBuffer(i, 'data');
    imageBase64 = buf.toString('base64');
    imageMimeType = (it.binary && it.binary.data && it.binary.data.mimeType) || orig.mimeType || 'image/jpeg';
  } catch(e) {
    out.push({ json: { ...orig, _download_error: String(e) } });
    continue;
  }
  out.push({ json: { ...orig, imageBase64, imageMimeType } });
}
return out;

// Build the Gemini generateContent body (per item) with structured output + 5-category prompt.
const cfg = $('Config').first().json;
const inp = $json;
if (inp._download_error) {
  return { json: { ...inp, _skip_llm: true } };
}
const prompt = `Sei un classificatore esperto di immagini e-commerce alimentari di Eataly. Classifica ogni immagine in UNA SOLA delle 5 categorie qui sotto.

1) FRONT
  - Prodotto confezionato visto FRONTALMENTE (logo centrato, lati assenti o trascurabili).
  - Vale anche se ci sono piccoli "props" alimentari accanto (fettina di pane vicino al vasetto di marmellata, qualche maccherone vicino al pacco di pasta).
  - Vale SEMPRE per BUNDLE e CESTI (set di piu prodotti come unico SKU), a prescindere dall'angolo di scatto.

2) NUDO_PACK
  - Confezione + prodotto "sfuso" della STESSA SKU, visibili nella stessa immagine.
  - Esempi: uovo di Pasqua + scatola, parmigiano confezionato + cuneo di formaggio, panettone + scatola.
  - La confezione DEVE essere visibile insieme al prodotto sfuso.

3) TOP
  - Prodotto confezionato visto DALL'ALTO (asse di scatto perpendicolare al piano).
  - Solo se l'angolo e chiaramente verticale; un'angolazione lieve = TREQUARTI o FRONT.

4) TREQUARTI
  - Prodotto confezionato a 3/4: si vede chiaramente uno spigolo laterale (>=15% del lato).
  - Se il lato e appena accennato (<15%) -> FRONT, non TREQUARTI.
  - Bundle/cesti -> restano FRONT anche se scattati a tre quarti.

5) SET
  - Prodotto NON confezionato, presentato su tagliere, piatto, coppa o ciotola.
  - Nessuna confezione visibile.
  - Vale anche per composite di piu prodotti diversi serviti insieme (es. cuneo di formaggio + crackers su tagliere).

REGOLE
- Una sola categoria. Non inventare etichette.
- In dubbio FRONT vs TREQUARTI -> FRONT.
- In dubbio NUDO_PACK vs SET -> confezione visibile? NUDO_PACK; nessuna confezione? SET.
- Bundle/cesti = sempre FRONT.

CONFIDENCE (0-100)
- 90-100: estremamente sicuro
- 70-89: sicuro
- 50-69: incerto
- <50: molto incerto

NEEDS_HUMAN_REVIEW
- true se confidence < 70
- false se confidence >= 70

OUTPUT: SOLO JSON valido, nessun testo extra.`;
const body = {
  contents: [{
    parts: [
      { inline_data: { mime_type: inp.imageMimeType, data: inp.imageBase64 } },
      { text: prompt }
    ]
  }],
  generationConfig: {
    temperature: 0,
    maxOutputTokens: 256,
    responseMimeType: 'application/json',
    responseJsonSchema: {
      type: 'object',
      properties: {
        output:             { type: 'string', enum: ['FRONT','NUDO_PACK','TOP','TREQUARTI','SET'] },
        confidence:         { type: 'integer', minimum: 0, maximum: 100 },
        needs_human_review: { type: 'boolean' }
      },
      required: ['output','confidence','needs_human_review']
    }
  }
};
return { json: { ...inp, _gemini_body: body, _model: cfg.geminiModel } };

// Per-item parser: emits one row formatted for the sheet, with the destination
// folder already resolved so the downstream Drive Move can use it directly.
function safeParse(s){
  if (!s) return null;
  let t = String(s).trim();
  const m = t.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (m) t = m[1].trim();
  try { return JSON.parse(t); } catch(e){}
  const a=t.indexOf('{'),b=t.lastIndexOf('}');
  if (a>=0&&b>a){ try{ return JSON.parse(t.slice(a,b+1)); }catch(e){} }
  return null;
}
const VALID = ['FRONT','NUDO_PACK','TOP','TREQUARTI','SET'];
const FOLDERS = {
  FRONT:        '15-oP9cJmzs5SQh0hyAhp1hTdi8ZDZBqR',
  NUDO_PACK:    '1pF6VshXDBte386yzsyzdW4fYoDfDsYzH',
  TOP:          '125a6QB5UJl22bozKWEQlyNDQaeDeL6K7',
  TREQUARTI:    '1qIxk1bzfzLy-lB5XUUk_WSfOISPsvLoy',
  SET:          '1CSIyBUbQe-aSzDUiJpnyh0KoZ17y0V0s',
  HUMAN_REVIEW: '10WbxpW9feowuLZ9nTilLtlFjWnUNdso1',
  FAILED:       '1cbAjxtdP1PmnAvprX9SdgMf5DvCd_wa2'
};
const SOURCE_FOLDER = '1vUrxw22LWZkkeDwGNO1P4sc8FK3Z3v2g';
const inp = $json;
let orig = {};
try { orig = $('Fan Out Files').itemMatching($itemIndex).json || {}; } catch(e) { orig = {}; }
const id = orig.id || inp.id || '';
const name = orig.name || inp.name || '';
const run_id = orig.run_id || inp.run_id || '';
const shard_id = orig.shard_id || inp.shard_id || '';
let output = '', confidence = 0, needs_human_review = true, parsing_error = null;
if (inp._download_error) {
  output = 'ERRORE_DOWNLOAD'; parsing_error = inp._download_error;
} else {
  const respRoot = inp.candidates ? inp : (inp.body || {});
  const choices = respRoot.candidates || [];
  let rawText = '';
  if (choices[0] && choices[0].content && choices[0].content.parts) {
    rawText = (choices[0].content.parts.map(p => p.text || '').join(' ') || '').trim();
  }
  const parsed = safeParse(rawText);
  if (parsed && typeof parsed === 'object') {
    output = String(parsed.output ?? '').trim().toUpperCase().replace(/ /g,'_');
    confidence = Math.max(0, Math.min(100, Number(parsed.confidence ?? 0) || 0));
    needs_human_review = (typeof parsed.needs_human_review === 'boolean') ? parsed.needs_human_review : (confidence < 70);
    if (!VALID.includes(output)) {
      parsing_error = `categoria_non_valida:${output}`;
      output = 'ERRORE_VALIDAZIONE';
      confidence = 0; needs_human_review = true;
    }
  } else {
    parsing_error = 'json_malformato';
    output = 'NON_DETERMINATO';
  }
}
// Decide where to move the file
const isFailure = parsing_error || ['ERRORE_DOWNLOAD','ERRORE_VALIDAZIONE','NON_DETERMINATO'].includes(output);
let dest_folder_id, cluster;
if (isFailure) { dest_folder_id = FOLDERS.FAILED; cluster = 'failed'; }
else if (confidence < 70) { dest_folder_id = FOLDERS.HUMAN_REVIEW; cluster = 'review'; }
else { dest_folder_id = FOLDERS[output] || FOLDERS.FAILED; cluster = 'auto'; }
return { json: {
  ID: id,
  'Nome immagine': name,
  Classificazione: output,
  Confidence: confidence,
  Cluster: cluster,
  dest_folder_id,
  source_folder_id: SOURCE_FOLDER,
  run_id, shard_id,
  parsing_error
}};
